INSERT INTO `article` VALUES ('https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/a94c137f33d249c28f3d03a12d2ac4da~tplv-k3u1fbpfcp-watermark.image?', 'iOS 15 把 AntV G2 搞挂了～', '这个版本的配色，和 AntV 的官网整体配色毫无违和感。 卡死的问题 ​ 没有任何报错，没有任何额外信息，就是卡死浏览器， 导致页面崩溃。只好一行一行代码的断点，从 G2 到 G 一两万行代码，以及直', '---↵theme: juejin↵highlight: agate↵---↵↵![火箭.svg](https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/1d83f1236394406a9ff9c6b161ae1980~tplv-k3u1fbpfcp-watermark.image)↵## Markdown Basic Syntax↵↵I just love **bold text**. Italicized text is the _cat\'s meow_. At the command prompt, type `nano`.↵↵My favorite markdown editor is [ByteMD](https://github.com/bytedance/bytemd).↵↵1. First item↵2. Second item↵3. Third item ↵↵> Dorothy followed her through many of the beautiful rooms in her castle.↵↵```js↵import { Editor, Viewer } from \'bytemd\';↵import gfm from \'@bytemd/plugin-gfm\';↵↵const plugins = [↵  gfm(),↵  // Add more plugins here↵];↵↵const editor = new Editor({↵  target: document.body, // DOM to render↵  props: {↵    value: \'\',↵    plugins,↵  },↵});↵↵editor.on(\'change\', (e) => {↵  editor.$set({ value: e.detail.value });↵});↵```↵↵## GFM Extended Syntax↵↵Automatic URL Linking: https://github.com/bytedance/bytemd↵↵~~The world is flat.~~ We now know that the world is round.↵↵- [x] Write the press release↵- [ ] Update the website↵- [ ] Contact the media↵↵| Syntax    | Description |↵| --------- | ----------- |↵| Header    | Title       |↵| Paragraph | Text        |↵↵## Footnotes↵↵Here\'s a simple footnote,[^1] and here\'s a longer one.[^bignote]↵↵[^1]: This is the first footnote.↵[^bignote]: Here\'s one with multiple paragraphs and code.↵↵    Indent paragraphs to include them in the footnote.↵↵    `{ my code }`↵↵    Add as many paragraphs as you like.↵', '<p><img src=\"https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/1d83f1236394406a9ff9c6b161ae1980~tplv-k3u1fbpfcp-watermark.image\" alt=\"火箭.svg\"></p>\n<h2>Markdown Basic Syntax</h2>\n<p>I just love <strong>bold text</strong>. Italicized text is the <em>cat\'s meow</em>. At the command prompt, type <code>nano</code>.</p>\n<p>My favorite markdown editor is <a href=\"https://github.com/bytedance/bytemd\" target=\"_blank\" rel=\"nofollow noopener noreferrer\">ByteMD</a>.</p>\n<ol>\n<li>First item</li>\n<li>Second item</li>\n<li>Third item</li>\n</ol>\n<blockquote>\n<p>Dorothy followed her through many of the beautiful rooms in her castle.</p>\n</blockquote>\n<pre><code class=\"hljs language-js\">    <span class=\"hljs-keyword\">import</span> { Editor, Viewer } <span class=\"hljs-keyword\">from</span> <span class=\"hljs-string\">\'bytemd\'</span>;\n    <span class=\"hljs-keyword\">import</span> gfm <span class=\"hljs-keyword\">from</span> <span class=\"hljs-string\">\'@bytemd/plugin-gfm\'</span>;\n\n    <span class=\"hljs-keyword\">const</span> plugins = [\n        gfm(),\n        <span class=\"hljs-comment\">// Add more plugins here</span>\n    ];\n        \n    <span class=\"hljs-keyword\">const</span> editor = <span class=\"hljs-keyword\">new</span> Editor({\n        <span class=\"hljs-attr\">target</span>: <span class=\"hljs-built_in\">document</span>.body, <span class=\"hljs-comment\">// DOM to render</span>\n        <span class=\"hljs-attr\">props</span>: {\n        <span class=\"hljs-attr\">value</span>: <span class=\"hljs-string\">\'\'</span>,\n        plugins,\n        },\n    });\n\n    editor.on(<span class=\"hljs-string\">\'change\'</span>, <span class=\"hljs-function\">(<span class=\"hljs-params\">e</span>) =&gt;</span> {\n    editor.$set({ <span class=\"hljs-attr\">value</span>: e.detail.value });\n});\n</code></pre>\n<h2>GFM Extended Syntax</h2>\n<p>Automatic URL Linking: <a href=\"https://github.com/bytedance/bytemd\" target=\"_blank\" rel=\"nofollow noopener noreferrer\">https://github.com/bytedance/bytemd</a></p>\n<p><del>The world is flat.</del> We now know that the world is round.</p>\n<ul class=\"contains-task-list\">\n<li class=\"task-list-item\"><input type=\"checkbox\" checked=\"\" disabled=\"\"> Write the press releas</li>\n<li class=\"task-list-item\"><input type=\"checkbox\" disabled=\"\"> Update the website</li>\n<li class=\"task-list-item\"><input type=\"checkbox\" disabled=\"\"> Contact the media</li>\n</ul>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Syntax</th><th>Description</th></tr></thead><tbody><tr><td>Header</td><td>Title</td></tr><tr><td>Paragraph</td><td>Text</td></tr></tbody></table>\n<h2>Footnotes</h2>\n<p>Here\'s a simple footnote,<sup id=\"user-content-fnref-1\"><a href=\"#fn-1\" class=\"footnote-ref\">1</a></sup> and here\'s a longer one.<sup id=\"user-content-fnref-bignote\"><a href=\"#fn-bignote\" class=\"footnote-ref\">bignote</a></sup></p>\n<p>Indent paragraphs to include them in the footnote.</p>\n<p><code>{ my code }</code></p>\n<p>Add as many paragraphs as you like.</p>\n<div class=\"footnotes\">\n<hr>\n<ol>\n<li id=\"user-content-fn-1\">This is the first footnote.<a href=\"#fnref-1\" class=\"footnote-backref\">↩</a></li>\n<li id=\"user-content-fn-bignote\">Here\'s one with multiple paragraphs and code.<a href=\"#fnref-bignote\" class=\"footnote-backref\">↩</a></li>\n</ol>\n</div><!--8-->', NULL, NULL, NULL, 0, '0', '1', 1, 'juejin', '', 7012161541378146334, NULL, '2022-03-15 16:19:59.023590', '2022-03-28 14:56:10.584561');
INSERT INTO `article` VALUES (NULL, '干掉Session？这个跨域认证解决方案真的优雅！', '用户登录认证是 Web 应用中非常常见的一个业务，一般的流程是这样的： 客户端向服务器端发送用户名和密码 服务器端验证通过后，在当前会话（session）中保存相关数据，比如说登录时间、登录 IP 等', '---↵theme: juejin↵highlight: agate↵---↵↵![火箭.svg](https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/1d83f1236394406a9ff9c6b161ae1980~tplv-k3u1fbpfcp-watermark.image)↵## Markdown Basic Syntax↵↵I just love **bold text**. Italicized text is the _cat\'s meow_. At the command prompt, type `nano`.↵↵My favorite markdown editor is [ByteMD](https://github.com/bytedance/bytemd).↵↵1. First item↵2. Second item↵3. Third item ↵↵> Dorothy followed her through many of the beautiful rooms in her castle.↵↵```js↵import { Editor, Viewer } from \'bytemd\';↵import gfm from \'@bytemd/plugin-gfm\';↵↵const plugins = [↵  gfm(),↵  // Add more plugins here↵];↵↵const editor = new Editor({↵  target: document.body, // DOM to render↵  props: {↵    value: \'\',↵    plugins,↵  },↵});↵↵editor.on(\'change\', (e) => {↵  editor.$set({ value: e.detail.value });↵});↵```↵↵## GFM Extended Syntax↵↵Automatic URL Linking: https://github.com/bytedance/bytemd↵↵~~The world is flat.~~ We now know that the world is round.↵↵- [x] Write the press release↵- [ ] Update the website↵- [ ] Contact the media↵↵| Syntax    | Description |↵| --------- | ----------- |↵| Header    | Title       |↵| Paragraph | Text        |↵↵## Footnotes↵↵Here\'s a simple footnote,[^1] and here\'s a longer one.[^bignote]↵↵[^1]: This is the first footnote.↵[^bignote]: Here\'s one with multiple paragraphs and code.↵↵    Indent paragraphs to include them in the footnote.↵↵    `{ my code }`↵↵    Add as many paragraphs as you like.↵', NULL, NULL, NULL, NULL, 0, '0', '1', 3, 'juejin', '', 7012161541378146335, NULL, '2022-03-15 16:19:59.023590', '2022-03-28 14:49:58.018863');
