INSERT INTO `article` VALUES (NULL, 'vue3+ts实现强大简易的管理异步数据请求的 Hook', 'vue+ts的异步管理数据的hook方案，每个人都能轻松优雅的管理自己的异步请求。拒绝重复代码，拒绝晦涩难懂的源码。', '---↵theme: juejin↵highlight: agate↵---↵↵![火箭.svg](https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/1d83f1236394406a9ff9c6b161ae1980~tplv-k3u1fbpfcp-watermark.image)↵## Markdown Basic Syntax↵↵I just love **bold text**. Italicized text is the _cat\'s meow_. At the command prompt, type `nano`.↵↵My favorite markdown editor is [ByteMD](https://github.com/bytedance/bytemd).↵↵1. First item↵2. Second item↵3. Third item ↵↵> Dorothy followed her through many of the beautiful rooms in her castle.↵↵```js↵import { Editor, Viewer } from \'bytemd\';↵import gfm from \'@bytemd/plugin-gfm\';↵↵const plugins = [↵  gfm(),↵  // Add more plugins here↵];↵↵const editor = new Editor({↵  target: document.body, // DOM to render↵  props: {↵    value: \'\',↵    plugins,↵  },↵});↵↵editor.on(\'change\', (e) => {↵  editor.$set({ value: e.detail.value });↵});↵```↵↵## GFM Extended Syntax↵↵Automatic URL Linking: https://github.com/bytedance/bytemd↵↵~~The world is flat.~~ We now know that the world is round.↵↵- [x] Write the press release↵- [ ] Update the website↵- [ ] Contact the media↵↵| Syntax    | Description |↵| --------- | ----------- |↵| Header    | Title       |↵| Paragraph | Text        |↵↵## Footnotes↵↵Here\'s a simple footnote,[^1] and here\'s a longer one.[^bignote]↵↵[^1]: This is the first footnote.↵[^bignote]: Here\'s one with multiple paragraphs and code.↵↵    Indent paragraphs to include them in the footnote.↵↵    `{ my code }`↵↵    Add as many paragraphs as you like.↵', NULL, NULL, NULL, NULL, 0, '0', '1', 2, 'juejin', '', 7012161541378146337, NULL, '2022-03-15 16:19:59.023590', '2022-03-28 14:50:05.796066');
INSERT INTO `article` VALUES (NULL, '封装 requestAnimationFrame 来代替 setTimeout', '最近看antdv 某些组件源码的时候发现，是使用requestAnimationFrame 来代替 setTimeout；下面我们就来看看是如何实现的； 首先 requestAnimationFram', '---↵theme: juejin↵highlight: agate↵---↵↵![火箭.svg](https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/1d83f1236394406a9ff9c6b161ae1980~tplv-k3u1fbpfcp-watermark.image)↵## Markdown Basic Syntax↵↵I just love **bold text**. Italicized text is the _cat\'s meow_. At the command prompt, type `nano`.↵↵My favorite markdown editor is [ByteMD](https://github.com/bytedance/bytemd).↵↵1. First item↵2. Second item↵3. Third item ↵↵> Dorothy followed her through many of the beautiful rooms in her castle.↵↵```js↵import { Editor, Viewer } from \'bytemd\';↵import gfm from \'@bytemd/plugin-gfm\';↵↵const plugins = [↵  gfm(),↵  // Add more plugins here↵];↵↵const editor = new Editor({↵  target: document.body, // DOM to render↵  props: {↵    value: \'\',↵    plugins,↵  },↵});↵↵editor.on(\'change\', (e) => {↵  editor.$set({ value: e.detail.value });↵});↵```↵↵## GFM Extended Syntax↵↵Automatic URL Linking: https://github.com/bytedance/bytemd↵↵~~The world is flat.~~ We now know that the world is round.↵↵- [x] Write the press release↵- [ ] Update the website↵- [ ] Contact the media↵↵| Syntax    | Description |↵| --------- | ----------- |↵| Header    | Title       |↵| Paragraph | Text        |↵↵## Footnotes↵↵Here\'s a simple footnote,[^1] and here\'s a longer one.[^bignote]↵↵[^1]: This is the first footnote.↵[^bignote]: Here\'s one with multiple paragraphs and code.↵↵    Indent paragraphs to include them in the footnote.↵↵    `{ my code }`↵↵    Add as many paragraphs as you like.↵', NULL, NULL, NULL, NULL, 0, '0', '1', 7, 'juejin', '', 7012161541378146338, NULL, '2022-03-15 16:19:59.023590', '2022-03-28 14:50:08.953951');
INSERT INTO `article` VALUES ('https://p9-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/23acee1319a8481fa9c9548b312cd18c~tplv-k3u1fbpfcp-watermark.image?', '产品说：“用户登陆要使用RSA加密才行”', '加密是开发中很常见的一个问题，主要目的是为了保护数据不被非法窃取、阅读。加密的算法也有很多种，常见的有：DES、RSA、AES、MD5等，', '---↵theme: juejin↵highlight: agate↵---↵↵![火箭.svg](https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/1d83f1236394406a9ff9c6b161ae1980~tplv-k3u1fbpfcp-watermark.image)↵## Markdown Basic Syntax↵↵I just love **bold text**. Italicized text is the _cat\'s meow_. At the command prompt, type `nano`.↵↵My favorite markdown editor is [ByteMD](https://github.com/bytedance/bytemd).↵↵1. First item↵2. Second item↵3. Third item ↵↵> Dorothy followed her through many of the beautiful rooms in her castle.↵↵```js↵import { Editor, Viewer } from \'bytemd\';↵import gfm from \'@bytemd/plugin-gfm\';↵↵const plugins = [↵  gfm(),↵  // Add more plugins here↵];↵↵const editor = new Editor({↵  target: document.body, // DOM to render↵  props: {↵    value: \'\',↵    plugins,↵  },↵});↵↵editor.on(\'change\', (e) => {↵  editor.$set({ value: e.detail.value });↵});↵```↵↵## GFM Extended Syntax↵↵Automatic URL Linking: https://github.com/bytedance/bytemd↵↵~~The world is flat.~~ We now know that the world is round.↵↵- [x] Write the press release↵- [ ] Update the website↵- [ ] Contact the media↵↵| Syntax    | Description |↵| --------- | ----------- |↵| Header    | Title       |↵| Paragraph | Text        |↵↵## Footnotes↵↵Here\'s a simple footnote,[^1] and here\'s a longer one.[^bignote]↵↵[^1]: This is the first footnote.↵[^bignote]: Here\'s one with multiple paragraphs and code.↵↵    Indent paragraphs to include them in the footnote.↵↵    `{ my code }`↵↵    Add as many paragraphs as you like.↵', NULL, NULL, NULL, NULL, 0, '0', '1', 2, 'juejin', '', 7012161541378146339, NULL, '2022-03-15 16:19:59.023590', '2022-03-28 14:50:12.609232');
INSERT INTO `article` VALUES ('https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/a94c137f33d249c28f3d03a12d2ac4da~tplv-k3u1fbpfcp-watermark.image?', 'pinia 踩坑总结', '最近在做项目调优，发现 pinia 真香，于是把之前的 vuex替换为 pinia，结果踩了一天的坑！', '---↵theme: juejin↵highlight: agate↵---↵↵![火箭.svg](https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/1d83f1236394406a9ff9c6b161ae1980~tplv-k3u1fbpfcp-watermark.image)↵## Markdown Basic Syntax↵↵I just love **bold text**. Italicized text is the _cat\'s meow_. At the command prompt, type `nano`.↵↵My favorite markdown editor is [ByteMD](https://github.com/bytedance/bytemd).↵↵1. First item↵2. Second item↵3. Third item ↵↵> Dorothy followed her through many of the beautiful rooms in her castle.↵↵```js↵import { Editor, Viewer } from \'bytemd\';↵import gfm from \'@bytemd/plugin-gfm\';↵↵const plugins = [↵  gfm(),↵  // Add more plugins here↵];↵↵const editor = new Editor({↵  target: document.body, // DOM to render↵  props: {↵    value: \'\',↵    plugins,↵  },↵});↵↵editor.on(\'change\', (e) => {↵  editor.$set({ value: e.detail.value });↵});↵```↵↵## GFM Extended Syntax↵↵Automatic URL Linking: https://github.com/bytedance/bytemd↵↵~~The world is flat.~~ We now know that the world is round.↵↵- [x] Write the press release↵- [ ] Update the website↵- [ ] Contact the media↵↵| Syntax    | Description |↵| --------- | ----------- |↵| Header    | Title       |↵| Paragraph | Text        |↵↵## Footnotes↵↵Here\'s a simple footnote,[^1] and here\'s a longer one.[^bignote]↵↵[^1]: This is the first footnote.↵[^bignote]: Here\'s one with multiple paragraphs and code.↵↵    Indent paragraphs to include them in the footnote.↵↵    `{ my code }`↵↵    Add as many paragraphs as you like.↵', NULL, NULL, NULL, NULL, 0, '0', '1', 11, 'juejin', '', 7012161541378146340, NULL, '2022-03-15 16:19:59.023590', '2022-03-28 14:50:15.444387');
INSERT INTO `article` VALUES (NULL, 'Fomir: 又一个表单轮子', '最近半年，一直在做表单相关的业务，加上自己多年浸淫表单的经验，根据自己感悟，造了一个表单轮子，取名为 Formir。 Github 地址：https://github.com/forsigner/fo', '---↵theme: juejin↵highlight: agate↵---↵↵![火箭.svg](https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/1d83f1236394406a9ff9c6b161ae1980~tplv-k3u1fbpfcp-watermark.image)↵## Markdown Basic Syntax↵↵I just love **bold text**. Italicized text is the _cat\'s meow_. At the command prompt, type `nano`.↵↵My favorite markdown editor is [ByteMD](https://github.com/bytedance/bytemd).↵↵1. First item↵2. Second item↵3. Third item ↵↵> Dorothy followed her through many of the beautiful rooms in her castle.↵↵```js↵import { Editor, Viewer } from \'bytemd\';↵import gfm from \'@bytemd/plugin-gfm\';↵↵const plugins = [↵  gfm(),↵  // Add more plugins here↵];↵↵const editor = new Editor({↵  target: document.body, // DOM to render↵  props: {↵    value: \'\',↵    plugins,↵  },↵});↵↵editor.on(\'change\', (e) => {↵  editor.$set({ value: e.detail.value });↵});↵```↵↵## GFM Extended Syntax↵↵Automatic URL Linking: https://github.com/bytedance/bytemd↵↵~~The world is flat.~~ We now know that the world is round.↵↵- [x] Write the press release↵- [ ] Update the website↵- [ ] Contact the media↵↵| Syntax    | Description |↵| --------- | ----------- |↵| Header    | Title       |↵| Paragraph | Text        |↵↵## Footnotes↵↵Here\'s a simple footnote,[^1] and here\'s a longer one.[^bignote]↵↵[^1]: This is the first footnote.↵[^bignote]: Here\'s one with multiple paragraphs and code.↵↵    Indent paragraphs to include them in the footnote.↵↵    `{ my code }`↵↵    Add as many paragraphs as you like.↵', NULL, NULL, NULL, NULL, 0, '0', '1', 6, 'juejin', '', 7012161541378146341, NULL, '2022-03-15 16:19:59.023590', '2022-03-28 14:50:18.324449');
