INSERT INTO `article` VALUES (NULL, '自动拦截 50% crash，字节自研 Fastbot 如何助力今日头条稳定性测试', 'Fastbot 是公司 Quality Lab 与 GIP - iOS 平台架构团队共同研发的智能化测试服务，其利用机器学习和强化学习进行遍历测试，提供了基础的稳定性测试服务能力。', '---↵theme: juejin↵highlight: agate↵---↵↵![火箭.svg](https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/1d83f1236394406a9ff9c6b161ae1980~tplv-k3u1fbpfcp-watermark.image)↵## Markdown Basic Syntax↵↵I just love **bold text**. Italicized text is the _cat\'s meow_. At the command prompt, type `nano`.↵↵My favorite markdown editor is [ByteMD](https://github.com/bytedance/bytemd).↵↵1. First item↵2. Second item↵3. Third item ↵↵> Dorothy followed her through many of the beautiful rooms in her castle.↵↵```js↵import { Editor, Viewer } from \'bytemd\';↵import gfm from \'@bytemd/plugin-gfm\';↵↵const plugins = [↵  gfm(),↵  // Add more plugins here↵];↵↵const editor = new Editor({↵  target: document.body, // DOM to render↵  props: {↵    value: \'\',↵    plugins,↵  },↵});↵↵editor.on(\'change\', (e) => {↵  editor.$set({ value: e.detail.value });↵});↵```↵↵## GFM Extended Syntax↵↵Automatic URL Linking: https://github.com/bytedance/bytemd↵↵~~The world is flat.~~ We now know that the world is round.↵↵- [x] Write the press release↵- [ ] Update the website↵- [ ] Contact the media↵↵| Syntax    | Description |↵| --------- | ----------- |↵| Header    | Title       |↵| Paragraph | Text        |↵↵## Footnotes↵↵Here\'s a simple footnote,[^1] and here\'s a longer one.[^bignote]↵↵[^1]: This is the first footnote.↵[^bignote]: Here\'s one with multiple paragraphs and code.↵↵    Indent paragraphs to include them in the footnote.↵↵    `{ my code }`↵↵    Add as many paragraphs as you like.↵', NULL, NULL, NULL, NULL, 0, '0', '1', 6, 'juejin', '', 7012161541378146346, NULL, '2022-03-15 16:19:59.023590', '2022-03-28 14:50:27.474807');
INSERT INTO `article` VALUES ('https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/5742a122b9ac44b38167f842f26538dd~tplv-k3u1fbpfcp-watermark.image?', '自己书写一个npm包并发布到npm上面/卸载', '自己书写一个npm包并发布到npm上面 说到npm包都会给人一种特别高大上的感觉，并且自己写了一个包之后如果有人用那么就会产生莫大的成就感，程序员的快乐就是这么简单。', '---↵theme: juejin↵highlight: agate↵---↵↵![火箭.svg](https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/1d83f1236394406a9ff9c6b161ae1980~tplv-k3u1fbpfcp-watermark.image)↵## Markdown Basic Syntax↵↵I just love **bold text**. Italicized text is the _cat\'s meow_. At the command prompt, type `nano`.↵↵My favorite markdown editor is [ByteMD](https://github.com/bytedance/bytemd).↵↵1. First item↵2. Second item↵3. Third item ↵↵> Dorothy followed her through many of the beautiful rooms in her castle.↵↵```js↵import { Editor, Viewer } from \'bytemd\';↵import gfm from \'@bytemd/plugin-gfm\';↵↵const plugins = [↵  gfm(),↵  // Add more plugins here↵];↵↵const editor = new Editor({↵  target: document.body, // DOM to render↵  props: {↵    value: \'\',↵    plugins,↵  },↵});↵↵editor.on(\'change\', (e) => {↵  editor.$set({ value: e.detail.value });↵});↵```↵↵## GFM Extended Syntax↵↵Automatic URL Linking: https://github.com/bytedance/bytemd↵↵~~The world is flat.~~ We now know that the world is round.↵↵- [x] Write the press release↵- [ ] Update the website↵- [ ] Contact the media↵↵| Syntax    | Description |↵| --------- | ----------- |↵| Header    | Title       |↵| Paragraph | Text        |↵↵## Footnotes↵↵Here\'s a simple footnote,[^1] and here\'s a longer one.[^bignote]↵↵[^1]: This is the first footnote.↵[^bignote]: Here\'s one with multiple paragraphs and code.↵↵    Indent paragraphs to include them in the footnote.↵↵    `{ my code }`↵↵    Add as many paragraphs as you like.↵', NULL, NULL, NULL, NULL, 0, '0', '1', NULL, 'juejin', '', 7012161541378146347, NULL, '2022-03-15 16:19:59.023590', '2022-03-15 16:28:17.877666');
INSERT INTO `article` VALUES ('https://p6-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/32f3d027cbc840ed900d3d6191b0c974~tplv-k3u1fbpfcp-watermark.image?', '【春哥故事会 02】 魔术姐的编程魔法', '入职之后，得知一位同事会“bug消失术”和“需求实现术”，不可谓不神奇。今天这一集，春哥带来了魔术姐的故事', '---↵theme: juejin↵highlight: agate↵---↵↵![火箭.svg](https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/1d83f1236394406a9ff9c6b161ae1980~tplv-k3u1fbpfcp-watermark.image)↵## Markdown Basic Syntax↵↵I just love **bold text**. Italicized text is the _cat\'s meow_. At the command prompt, type `nano`.↵↵My favorite markdown editor is [ByteMD](https://github.com/bytedance/bytemd).↵↵1. First item↵2. Second item↵3. Third item ↵↵> Dorothy followed her through many of the beautiful rooms in her castle.↵↵```js↵import { Editor, Viewer } from \'bytemd\';↵import gfm from \'@bytemd/plugin-gfm\';↵↵const plugins = [↵  gfm(),↵  // Add more plugins here↵];↵↵const editor = new Editor({↵  target: document.body, // DOM to render↵  props: {↵    value: \'\',↵    plugins,↵  },↵});↵↵editor.on(\'change\', (e) => {↵  editor.$set({ value: e.detail.value });↵});↵```↵↵## GFM Extended Syntax↵↵Automatic URL Linking: https://github.com/bytedance/bytemd↵↵~~The world is flat.~~ We now know that the world is round.↵↵- [x] Write the press release↵- [ ] Update the website↵- [ ] Contact the media↵↵| Syntax    | Description |↵| --------- | ----------- |↵| Header    | Title       |↵| Paragraph | Text        |↵↵## Footnotes↵↵Here\'s a simple footnote,[^1] and here\'s a longer one.[^bignote]↵↵[^1]: This is the first footnote.↵[^bignote]: Here\'s one with multiple paragraphs and code.↵↵    Indent paragraphs to include them in the footnote.↵↵    `{ my code }`↵↵    Add as many paragraphs as you like.↵', NULL, NULL, NULL, NULL, 0, '0', '1', NULL, 'juejin', '', 7012161541378146348, NULL, '2022-03-15 16:19:59.023590', '2022-03-15 16:28:33.901689');
INSERT INTO `article` VALUES (NULL, 'IDE 中的魔法 - 如何实现一个 parser', '我们已经在前文中简单了解了 ANTLR 及其基本的用法，现在，我们就开始正式的静态分析之旅：编译 Excel 的公式，并实现自动补全的功能。而第一步，我们需要实现能够编译公式的 parser。', '---↵theme: juejin↵highlight: agate↵---↵↵![火箭.svg](https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/1d83f1236394406a9ff9c6b161ae1980~tplv-k3u1fbpfcp-watermark.image)↵## Markdown Basic Syntax↵↵I just love **bold text**. Italicized text is the _cat\'s meow_. At the command prompt, type `nano`.↵↵My favorite markdown editor is [ByteMD](https://github.com/bytedance/bytemd).↵↵1. First item↵2. Second item↵3. Third item ↵↵> Dorothy followed her through many of the beautiful rooms in her castle.↵↵```js↵import { Editor, Viewer } from \'bytemd\';↵import gfm from \'@bytemd/plugin-gfm\';↵↵const plugins = [↵  gfm(),↵  // Add more plugins here↵];↵↵const editor = new Editor({↵  target: document.body, // DOM to render↵  props: {↵    value: \'\',↵    plugins,↵  },↵});↵↵editor.on(\'change\', (e) => {↵  editor.$set({ value: e.detail.value });↵});↵```↵↵## GFM Extended Syntax↵↵Automatic URL Linking: https://github.com/bytedance/bytemd↵↵~~The world is flat.~~ We now know that the world is round.↵↵- [x] Write the press release↵- [ ] Update the website↵- [ ] Contact the media↵↵| Syntax    | Description |↵| --------- | ----------- |↵| Header    | Title       |↵| Paragraph | Text        |↵↵## Footnotes↵↵Here\'s a simple footnote,[^1] and here\'s a longer one.[^bignote]↵↵[^1]: This is the first footnote.↵[^bignote]: Here\'s one with multiple paragraphs and code.↵↵    Indent paragraphs to include them in the footnote.↵↵    `{ my code }`↵↵    Add as many paragraphs as you like.↵', NULL, NULL, NULL, NULL, 0, '0', '1', 2, 'juejin', '', 7012161541378146349, NULL, '2022-03-15 16:19:59.023590', '2022-03-28 14:50:31.753750');
INSERT INTO `article` VALUES (NULL, '针对JS中是否改变原数组的操作方法总结', '前端开发中，经常用到JavaScript数组操作，本文以是否改变原数组作分类，可当做api直接拿来用。', '---↵theme: juejin↵highlight: agate↵---↵↵![火箭.svg](https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/1d83f1236394406a9ff9c6b161ae1980~tplv-k3u1fbpfcp-watermark.image)↵## Markdown Basic Syntax↵↵I just love **bold text**. Italicized text is the _cat\'s meow_. At the command prompt, type `nano`.↵↵My favorite markdown editor is [ByteMD](https://github.com/bytedance/bytemd).↵↵1. First item↵2. Second item↵3. Third item ↵↵> Dorothy followed her through many of the beautiful rooms in her castle.↵↵```js↵import { Editor, Viewer } from \'bytemd\';↵import gfm from \'@bytemd/plugin-gfm\';↵↵const plugins = [↵  gfm(),↵  // Add more plugins here↵];↵↵const editor = new Editor({↵  target: document.body, // DOM to render↵  props: {↵    value: \'\',↵    plugins,↵  },↵});↵↵editor.on(\'change\', (e) => {↵  editor.$set({ value: e.detail.value });↵});↵```↵↵## GFM Extended Syntax↵↵Automatic URL Linking: https://github.com/bytedance/bytemd↵↵~~The world is flat.~~ We now know that the world is round.↵↵- [x] Write the press release↵- [ ] Update the website↵- [ ] Contact the media↵↵| Syntax    | Description |↵| --------- | ----------- |↵| Header    | Title       |↵| Paragraph | Text        |↵↵## Footnotes↵↵Here\'s a simple footnote,[^1] and here\'s a longer one.[^bignote]↵↵[^1]: This is the first footnote.↵[^bignote]: Here\'s one with multiple paragraphs and code.↵↵    Indent paragraphs to include them in the footnote.↵↵    `{ my code }`↵↵    Add as many paragraphs as you like.↵', '<article itemscope=\"itemscope\" itemtype=\"http://schema.org/Article\" data-entry-id=\"7087134135193436197\" data-draft-id=\"7086672546598223880\" data-original-type=\"0\" class=\"article\" style=\"\" data-v-3fbea7fe=\"\" data-v-4fa4e5da=\"\"><!----> <meta itemprop=\"headline\" content=\"前端算法入门一：刷算法题常用的JS基础扫盲\"> <meta itemprop=\"keywords\" content=\"前端,算法\"> <meta itemprop=\"datePublished\" content=\"2022-04-16T09:40:21.000Z\"> <meta itemprop=\"image\" content=\"https://p1-jj.byteimg.com/tos-cn-i-t2oaga2asx/gold-assets/icon/icon-128.png~tplv-t2oaga2asx-image.image\"> <div itemprop=\"author\" itemscope=\"itemscope\" itemtype=\"http://schema.org/Person\"><meta itemprop=\"name\" content=\"摆草猿\"> <meta itemprop=\"url\" content=\"https://juejin.cn/user/2718454174717518\"></div> <div itemprop=\"publisher\" itemscope=\"itemscope\" itemtype=\"http://schema.org/Organization\"><meta itemprop=\"name\" content=\"掘金\"> <div itemprop=\"logo\" itemscope=\"itemscope\" itemtype=\"https://schema.org/ImageObject\"><meta itemprop=\"url\" content=\"https://p1-jj.byteimg.com/tos-cn-i-t2oaga2asx/gold-assets/icon/icon-white-180.png~tplv-t2oaga2asx-image.image\"> <meta itemprop=\"width\" content=\"180\"> <meta itemprop=\"height\" content=\"180\"></div></div> <h1 data-v-3fbea7fe=\"\" class=\"article-title\">\n            前端算法入门一：刷算法题常用的JS基础扫盲\n            <!----></h1> <div data-v-3fbea7fe=\"\" class=\"author-info-block\"><a data-v-3fbea7fe=\"\" href=\"/user/2718454174717518\" target=\"_blank\" rel=\"\" class=\"avatar-link\"><img data-v-0808752c=\"\" data-v-3aafff8a=\"\" data-v-3fbea7fe=\"\" src=\"https://p9-passport.byteacctimg.com/img/user-avatar/11a4cab54cd5a515af06b53232d52179~300x300.image\" data-src=\"https://p9-passport.byteacctimg.com/img/user-avatar/11a4cab54cd5a515af06b53232d52179~300x300.image\" alt=\"\" loading=\"lazy\" class=\"lazy avatar avatar\"></a> <div data-v-3fbea7fe=\"\" class=\"author-info-box\"><div data-v-3fbea7fe=\"\" class=\"author-name\"><a data-v-2ecffe9f=\"\" data-v-3fbea7fe=\"\" href=\"/user/2718454174717518\" target=\"_blank\" rel=\"\" class=\"username username ellipsis\"><span data-v-2ecffe9f=\"\" class=\"name\" style=\"max-width: 128px;\">\n      摆草猿\n    </span> <span data-v-3acffd25=\"\" data-v-2ecffe9f=\"\" blank=\"true\" class=\"rank\"><img data-v-3acffd25=\"\" src=\"//lf3-cdn-tos.bytescm.com/obj/static/xitu_juejin_web/f597b88d22ce5370bd94495780459040.svg\" alt=\"lv-2\"></span> </a></div> <div data-v-3fbea7fe=\"\" class=\"meta-box\"><time data-v-3fbea7fe=\"\" datetime=\"2022-04-16T09:40:21.000Z\" title=\"Sat Apr 16 2022 17:40:21 GMT+0800 (中国标准时间)\" class=\"time\">\n                    2022年04月16日 17:40\n                  </time> <span data-v-3fbea7fe=\"\" class=\"views-count\">\n                    ·&nbsp;&nbsp;阅读 7147\n                  </span> <!----></div> <!----></div> <button data-v-565dd611=\"\" data-v-3fbea7fe=\"\" class=\"follow-button follow\"><span data-v-565dd611=\"\" class=\"icon icon-follow\"></span> <span data-v-565dd611=\"\" data-text=\"取消关注\" class=\"text\">关注</span></button></div> <!----> <!----> <!----> <div data-v-3fbea7fe=\"\" class=\"article-content\" itemprop=\"articleBody\"><div class=\"markdown-body\"><style>.markdown-body{word-break:break-word;line-height:1.75;font-weight:400;font-size:16px;overflow-x:hidden;color:#333}.markdown-body h1,.markdown-body h2,.markdown-body h3,.markdown-body h4,.markdown-body h5,.markdown-body h6{line-height:1.5;margin-top:35px;margin-bottom:10px;padding-bottom:5px}.markdown-body h1{font-size:24px;margin-bottom:5px}.markdown-body h2,.markdown-body h3,.markdown-body h4,.markdown-body h5,.markdown-body h6{font-size:20px}.markdown-body h2{padding-bottom:12px;border-bottom:1px solid #ececec}.markdown-body h3{font-size:18px;padding-bottom:0}.markdown-body h6{margin-top:5px}.markdown-body p{line-height:inherit;margin-top:22px;margin-bottom:22px}.markdown-body img{max-width:100%}.markdown-body hr{border:none;border-top:1px solid #ddd;margin-top:32px;margin-bottom:32px}.markdown-body code{word-break:break-word;border-radius:2px;overflow-x:auto;background-color:#fff5f5;color:#ff502c;font-size:.87em;padding:.065em .4em}.markdown-body code,.markdown-body pre{font-family:Menlo,Monaco,Consolas,Courier New,monospace}.markdown-body pre{overflow:auto;position:relative;line-height:1.75}.markdown-body pre>code{font-size:12px;padding:15px 12px;margin:0;word-break:normal;display:block;overflow-x:auto;color:#333;background:#f8f8f8}.markdown-body a{text-decoration:none;color:#0269c8;border-bottom:1px solid #d1e9ff}.markdown-body a:active,.markdown-body a:hover{color:#275b8c}.markdown-body table{display:inline-block!important;font-size:12px;width:auto;max-width:100%;overflow:auto;border:1px solid #f6f6f6}.markdown-body thead{background:#f6f6f6;color:#000;text-align:left}.markdown-body tr:nth-child(2n){background-color:#fcfcfc}.markdown-body td,.markdown-body th{padding:12px 7px;line-height:24px}.markdown-body td{min-width:120px}.markdown-body blockquote{color:#666;padding:1px 23px;margin:22px 0;border-left:4px solid #cbcbcb;background-color:#f8f8f8}.markdown-body blockquote:after{display:block;content:\"\"}.markdown-body blockquote>p{margin:10px 0}.markdown-body ol,.markdown-body ul{padding-left:28px}.markdown-body ol li,.markdown-body ul li{margin-bottom:0;list-style:inherit}.markdown-body ol li .task-list-item,.markdown-body ul li .task-list-item{list-style:none}.markdown-body ol li .task-list-item ol,.markdown-body ol li .task-list-item ul,.markdown-body ul li .task-list-item ol,.markdown-body ul li .task-list-item ul{margin-top:0}.markdown-body ol ol,.markdown-body ol ul,.markdown-body ul ol,.markdown-body ul ul{margin-top:3px}.markdown-body ol li{padding-left:6px}.markdown-body .contains-task-list{padding-left:0}.markdown-body .task-list-item{list-style:none}@media (max-width:720px){.markdown-body h1{font-size:24px}.markdown-body h2{font-size:20px}.markdown-body h3{font-size:18px}}</style><h2 data-id=\"heading-0\">介绍</h2>\n<p>此篇属于前端算法入门系列的第一篇，主要介绍常用的<code>数组方法</code>、<code>字符串方法</code>、<code>遍历方法</code>、<code>高阶函数</code>、<code>正则表达式</code>以及相关<code>数学知识</code>。</p>\n<ul>\n<li><a href=\"https://juejin.cn/post/7087134135193436197\" target=\"_blank\" title=\"https://juejin.cn/post/7087134135193436197\">前端算法入门一：刷算法题常用的JS基础扫盲</a></li>\n<li><a href=\"https://juejin.cn/post/7087286814230183943\" target=\"_blank\" title=\"https://juejin.cn/post/7087286814230183943\">前端算法入门二：时间空间复杂度&amp;8大数据结构的JS实现</a></li>\n<li><a href=\"https://juejin.cn/post/7088725301974269960\" target=\"_blank\" title=\"https://juejin.cn/post/7088725301974269960\">前端算法入门三：5大排序算法&amp;2大搜索&amp;4大算法思想</a></li>\n</ul>\n<blockquote>\n<p><strong>文章主要包含以下内容：</strong></p>\n<ul>\n<li>数组常用方法</li>\n<li>字符串常用方法</li>\n<li>常用遍历方法&amp;高阶函数</li>\n<li>常用正则表达式</li>\n<li>数学知识</li>\n</ul>\n</blockquote>\n<h2 data-id=\"heading-1\">一、数组常用方法</h2>\n<h3 data-id=\"heading-2\">1.push()</h3>\n<p>在尾部追加，类似于压栈，原数组会变。</p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> arr = [<span class=\"hljs-number\">1</span>, <span class=\"hljs-number\">2</span>, <span class=\"hljs-number\">3</span>]\narr.push(<span class=\"hljs-number\">8</span>)\n<span class=\"hljs-built_in\">console</span>.log(arr) <span class=\"hljs-comment\">// [1, 2, 3, 8]</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-3\">2.pop()</h3>\n<p>在尾部弹出，类似于出栈，原数组会变。数组的 <code>push</code> &amp; <code>pop</code> 可以模拟常见数据结构之一：栈。</p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> arr = [<span class=\"hljs-number\">1</span>, <span class=\"hljs-number\">2</span>, <span class=\"hljs-number\">3</span>]\n<span class=\"hljs-keyword\">const</span> popVal = arr.pop()\n<span class=\"hljs-built_in\">console</span>.log(popVal) <span class=\"hljs-comment\">// 3</span>\n<span class=\"hljs-built_in\">console</span>.log(arr) <span class=\"hljs-comment\">// [1, 2]</span>\n\n<span class=\"hljs-comment\">// 数组模拟常见数据结构之一：栈</span>\n<span class=\"hljs-keyword\">const</span> stack = [<span class=\"hljs-number\">0</span>, <span class=\"hljs-number\">1</span>]\nstack.push(<span class=\"hljs-number\">2</span>) <span class=\"hljs-comment\">// 压栈</span>\n<span class=\"hljs-built_in\">console</span>.log(stack) <span class=\"hljs-comment\">// [0, 1, 2]</span>\n\n<span class=\"hljs-keyword\">const</span> popValue = stack.pop() <span class=\"hljs-comment\">// 出栈</span>\n<span class=\"hljs-built_in\">console</span>.log(popValue) <span class=\"hljs-comment\">// 2</span>\n<span class=\"hljs-built_in\">console</span>.log(stack) <span class=\"hljs-comment\">// [0, 1]</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-4\">3.unshift()</h3>\n<p>在头部压入数据，类似于入队，原数组会变。</p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> arr = [<span class=\"hljs-number\">1</span>, <span class=\"hljs-number\">2</span>, <span class=\"hljs-number\">3</span>]\narr.unshift(<span class=\"hljs-number\">0</span>)\n<span class=\"hljs-built_in\">console</span>.log(arr) <span class=\"hljs-comment\">// [0, 1, 2, 3]</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-5\">4.shift()</h3>\n<p>在头部弹出数据，原数组会变。数组的 <code>push</code>（入队） &amp; <code>shift</code>（出队） 可以模拟常见数据结构之一：队列。</p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> arr = [<span class=\"hljs-number\">1</span>, <span class=\"hljs-number\">2</span>, <span class=\"hljs-number\">3</span>]\n<span class=\"hljs-keyword\">const</span> shiftVal = arr.shift()\n<span class=\"hljs-built_in\">console</span>.log(shiftVal) <span class=\"hljs-comment\">// 1</span>\n<span class=\"hljs-built_in\">console</span>.log(arr) <span class=\"hljs-comment\">// [2, 3]</span>\n\n<span class=\"hljs-comment\">// 数组模拟常见数据结构之一：队列</span>\n<span class=\"hljs-keyword\">const</span> queue = [<span class=\"hljs-number\">0</span>, <span class=\"hljs-number\">1</span>]\nqueue.push(<span class=\"hljs-number\">2</span>) <span class=\"hljs-comment\">// 入队</span>\n<span class=\"hljs-built_in\">console</span>.log(queue) <span class=\"hljs-comment\">// [0, 1, 2]</span>\n\n<span class=\"hljs-keyword\">const</span> shiftValue = queue.shift() <span class=\"hljs-comment\">// 出队</span>\n<span class=\"hljs-built_in\">console</span>.log(shiftValue) <span class=\"hljs-comment\">// 0</span>\n<span class=\"hljs-built_in\">console</span>.log(queue) <span class=\"hljs-comment\">// [1, 2]</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-6\">5.concat()</h3>\n<p><code>concat</code>会在当前数组尾部拼接传入的数组，然后返回一个新数组，原数组不变。</p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> arr = [<span class=\"hljs-number\">1</span>, <span class=\"hljs-number\">2</span>, <span class=\"hljs-number\">3</span>]\n<span class=\"hljs-keyword\">const</span> arr2 = arr.concat([<span class=\"hljs-number\">7</span>, <span class=\"hljs-number\">8</span>, <span class=\"hljs-number\">9</span>])\n<span class=\"hljs-built_in\">console</span>.log(arr) <span class=\"hljs-comment\">// [1, 2, 3]</span>\n<span class=\"hljs-built_in\">console</span>.log(arr2) <span class=\"hljs-comment\">// [1, 2, 3, 7, 8, 9]</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-7\">6.indexOf()</h3>\n<p>在数组中寻找该值，找到则返回其下标，找不到则返回<code>-1</code>。</p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> arr = [<span class=\"hljs-number\">1</span>, <span class=\"hljs-number\">2</span>, <span class=\"hljs-number\">3</span>]\n<span class=\"hljs-built_in\">console</span>.log(arr.indexOf(<span class=\"hljs-number\">2</span>)) <span class=\"hljs-comment\">// 1</span>\n<span class=\"hljs-built_in\">console</span>.log(arr.indexOf(<span class=\"hljs-number\">0</span>)) <span class=\"hljs-comment\">// -1</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-8\">7.includes()</h3>\n<p>在数组中寻找该值，找到则返回<code>true</code>，找不到则返回<code>false</code>。</p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> arr = [<span class=\"hljs-number\">1</span>, <span class=\"hljs-number\">2</span>, <span class=\"hljs-number\">3</span>]\n<span class=\"hljs-built_in\">console</span>.log(arr.includes(<span class=\"hljs-number\">2</span>)) <span class=\"hljs-comment\">// true</span>\n<span class=\"hljs-built_in\">console</span>.log(arr.includes(<span class=\"hljs-number\">4</span>)) <span class=\"hljs-comment\">// false</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-9\">8.join()</h3>\n<p>将数组转化成字符串，并返回该字符串，不传值则默认逗号隔开，原数组不变。</p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> arr = [<span class=\"hljs-number\">1</span>, <span class=\"hljs-number\">2</span>, <span class=\"hljs-number\">3</span>]\n<span class=\"hljs-built_in\">console</span>.log(arr.join()) <span class=\"hljs-comment\">// ‘1, 2, 3’</span>\n<span class=\"hljs-built_in\">console</span>.log(arr) <span class=\"hljs-comment\">// [1, 2, 3]</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-10\">9.reverse()</h3>\n<p>翻转原数组，并返回已完成翻转的数组，原数组改变。</p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> arr = [<span class=\"hljs-number\">1</span>, <span class=\"hljs-number\">2</span>, <span class=\"hljs-number\">3</span>]\n<span class=\"hljs-built_in\">console</span>.log(arr.reverse()) <span class=\"hljs-comment\">// [3, 2, 1]</span>\n<span class=\"hljs-built_in\">console</span>.log(arr) <span class=\"hljs-comment\">// [3, 2, 1]</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-11\">10.slice(start，end)</h3>\n<p>从<code>start</code> 开始截取到<code>end</code>，但是不包括<code>end</code></p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> arr = [<span class=\"hljs-number\">1</span>, <span class=\"hljs-number\">2</span>, <span class=\"hljs-number\">3</span>, <span class=\"hljs-number\">4</span>, <span class=\"hljs-number\">5</span>]\n<span class=\"hljs-built_in\">console</span>.log(arr.slice(<span class=\"hljs-number\">1</span>, <span class=\"hljs-number\">4</span>)) <span class=\"hljs-comment\">// [2, 3, 4]</span>\n<span class=\"hljs-built_in\">console</span>.log(arr) <span class=\"hljs-comment\">// [1, 2, 3, 4, 5]</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-12\">11.splice(start, deleteCount, item1, item2……)</h3>\n<ul>\n<li><code>start</code>参数 开始的位置</li>\n<li><code>deleteCount</code>要截取的个数</li>\n<li>后面的<code>items</code>为要添加的元素</li>\n<li>如果<code>deleteCount</code>为<code>0</code>，则表示不删除元素，从<code>start</code>位置开始添加后面的几个元素到原始的数组里面。</li>\n<li>返回值为由被删除的元素组成的一个数组。如果只删除了一个元素，则返回只包含一个元素的数组。如果没有删除元素，则返回空数组。</li>\n<li>这个方法会改变原始数组，数组的长度会发生变化</li>\n</ul>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> arr3 = [<span class=\"hljs-number\">1</span>, <span class=\"hljs-number\">2</span>, <span class=\"hljs-number\">3</span>, <span class=\"hljs-number\">4</span>, <span class=\"hljs-number\">5</span>, <span class=\"hljs-number\">6</span>, <span class=\"hljs-number\">7</span>, <span class=\"hljs-string\">\"f1\"</span>, <span class=\"hljs-string\">\"f2\"</span>];\n<span class=\"hljs-keyword\">const</span> arr4 = arr3.splice(<span class=\"hljs-number\">2</span>, <span class=\"hljs-number\">3</span>) <span class=\"hljs-comment\">// 删除第三个元素以后的三个数组元素(包含第三个元素)</span>\n<span class=\"hljs-built_in\">console</span>.log(arr4); <span class=\"hljs-comment\">// [3, 4, 5];</span>\n<span class=\"hljs-built_in\">console</span>.log(arr3); <span class=\"hljs-comment\">// [1, 2, 6, 7, \"f1\", \"f2\"]; 原始数组被改变</span>\n\n<span class=\"hljs-keyword\">const</span> arr5 = arr3.splice(<span class=\"hljs-number\">2</span>, <span class=\"hljs-number\">0</span>, <span class=\"hljs-string\">\"wu\"</span>, <span class=\"hljs-string\">\"leon\"</span>); \n<span class=\"hljs-comment\">// 从第2位开始删除0个元素，插入\"wu\",\"leon\"</span>\n<span class=\"hljs-built_in\">console</span>.log(arr5); <span class=\"hljs-comment\">// [] 返回空数组</span>\n<span class=\"hljs-built_in\">console</span>.log(arr3); <span class=\"hljs-comment\">// [1, 2, \"wu\", \"leon\", 6, 7, \"f1\", \"f2\"]; 原始数组被改变</span>\n\n<span class=\"hljs-keyword\">const</span> arr6 = arr3.splice(<span class=\"hljs-number\">2</span>, <span class=\"hljs-number\">3</span>, <span class=\"hljs-string\">\"xiao\"</span>, <span class=\"hljs-string\">\"long\"</span>);\n<span class=\"hljs-comment\">// 从第 2 位开始删除 3 个元素，插入\"xiao\", \"long\"</span>\n<span class=\"hljs-built_in\">console</span>.log(arr6); <span class=\"hljs-comment\">// [\"wu\", \"leon\", 6]</span>\n<span class=\"hljs-built_in\">console</span>.log(arr3); <span class=\"hljs-comment\">//[ 1, 2, \"xiao\", \"long\", 7, \"f1\", \"f2\"]</span>\n\n<span class=\"hljs-keyword\">const</span> arr7 = arr3.splice(<span class=\"hljs-number\">2</span>); <span class=\"hljs-comment\">// 从第三个元素开始删除所有的元素</span>\n<span class=\"hljs-built_in\">console</span>.log(arr7);<span class=\"hljs-comment\">// [\"xiao\", \"long\", 7, \"f1\", \"f2\"]</span>\n<span class=\"hljs-built_in\">console</span>.log(arr3); <span class=\"hljs-comment\">// [1, 2]</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-13\">12.sort()</h3>\n<ul>\n<li>对数组的元素进行排序，并返回数组。</li>\n<li>默认排序顺序是在将元素转换为字符串，然后比较它们的<code>UTF-16</code>代码单元值序列时构建的。</li>\n<li>由于它取决于具体实现，因此无法保证排序的时间和空间复杂性。</li>\n</ul>\n<p>可参考 <a href=\"https://link.juejin.cn?target=https%3A%2F%2Fdeveloper.mozilla.org%2Fzh-CN%2Fdocs%2FWeb%2FJavaScript%2FReference%2FGlobal_Objects%2FArray%2Fsort\" target=\"_blank\" rel=\"nofollow noopener noreferrer\" title=\"https://developer.mozilla.org/zh-CN/docs/Web/JavaScript/Reference/Global_Objects/Array/sort\" ref=\"nofollow noopener noreferrer\">MDN：Sort</a></p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> arr = [<span class=\"hljs-number\">1</span>, <span class=\"hljs-number\">2</span>, <span class=\"hljs-number\">3</span>]\narr.sort(<span class=\"hljs-function\">(<span class=\"hljs-params\">a, b</span>) =&gt;</span> b - a)\n<span class=\"hljs-built_in\">console</span>.log(arr) <span class=\"hljs-comment\">// [3, 2, 1]</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-14\">13.toString()</h3>\n<p>将数组转化成字符串，并返回该字符串，逗号隔开，原数组不变。</p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> arr = [<span class=\"hljs-number\">1</span>, <span class=\"hljs-number\">2</span>, <span class=\"hljs-number\">3</span>, <span class=\"hljs-number\">4</span>, <span class=\"hljs-number\">5</span>]\n<span class=\"hljs-built_in\">console</span>.log(arr.toString()) <span class=\"hljs-comment\">// ‘1, 2, 3, 4, 5’</span>\n<span class=\"hljs-built_in\">console</span>.log(arr) <span class=\"hljs-comment\">// [1, 2, 3, 4, 5]</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h2 data-id=\"heading-15\">二、字符串常用方法</h2>\n<h3 data-id=\"heading-16\">1.charAt()</h3>\n<p>返回指定索引位置处的字符。类似于数组用中括号获取相应下标位置的数据。</p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">var</span> str = <span class=\"hljs-string\">\'abcdefg\'</span>\n<span class=\"hljs-built_in\">console</span>.log(str.charAt(<span class=\"hljs-number\">2</span>)) <span class=\"hljs-comment\">// 输出 \'c\' </span>\n<span class=\"hljs-built_in\">console</span>.log(str[<span class=\"hljs-number\">2</span>]) <span class=\"hljs-comment\">// 输出 \'c\'</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-17\">2.concat()</h3>\n<p>类似数组的concat()，用来返回一个合并拼接两个或两个以上字符串。原字符串不变。</p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> str1 = <span class=\"hljs-string\">\'abcdefg\'</span>\n<span class=\"hljs-keyword\">const</span> str2 = <span class=\"hljs-string\">\'1234567\'</span>\n<span class=\"hljs-keyword\">const</span> str3 = str1.concat(str2)\n<span class=\"hljs-built_in\">console</span>.log(str3) <span class=\"hljs-comment\">// 输出 \'abcdefg1234567\'</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-18\">3.indexOf()、lastIndexOf()</h3>\n<p><code>indexOf</code>,返回一个字符在字符串中首次出现的位置,<code>lastIndexOf</code>返回一个字符在字符串中最后一次出现的位置。</p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> str = <span class=\"hljs-string\">\'abcdcefcg\'</span>\n<span class=\"hljs-built_in\">console</span>.log(str.indexOf(<span class=\"hljs-string\">\'c\'</span>)) <span class=\"hljs-comment\">// 输出 \'2\'</span>\n<span class=\"hljs-built_in\">console</span>.log(str.lastIndexOf(<span class=\"hljs-string\">\'c\'</span>)) <span class=\"hljs-comment\">// 输出 \'7\'</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-19\">4.slice()</h3>\n<p>提取字符串的片断，并把提取的字符串作为新的字符串返回出来。原字符串不变。</p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> str = <span class=\"hljs-string\">\'abcdefg\'</span>\n<span class=\"hljs-built_in\">console</span>.log(str.slice()) <span class=\"hljs-comment\">// 输出 \'abcdefg\', 不传递参数默认复制整个字符串</span>\n<span class=\"hljs-built_in\">console</span>.log(str.slice(<span class=\"hljs-number\">1</span>)) <span class=\"hljs-comment\">// 输出 \'bcdefg\',传递一个，则为提取的起点，然后到字符串结尾</span>\n<span class=\"hljs-built_in\">console</span>.log(str.slice(<span class=\"hljs-number\">2</span>, str.length-<span class=\"hljs-number\">1</span>)) <span class=\"hljs-comment\">// 输出\'cdef\',传递两个，为提取的起始点和结束点</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-20\">5.split()</h3>\n<p>使用指定的分隔符将一个字符串拆分为多个子字符串数组并返回，原字符串不变。</p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> str = <span class=\"hljs-string\">\'A*B*C*D*E*F*G\'</span>\n<span class=\"hljs-built_in\">console</span>.log(str.split(<span class=\"hljs-string\">\'*\'</span>)) <span class=\"hljs-comment\">// 输出 [\"A\", \"B\", \"C\", \"D\", \"E\", \"F\", \"G\"]</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-21\">6.substr(), substring()</h3>\n<ul>\n<li>这两个方法的功能都是截取一个字符串的片段，并返回截取的字符串。</li>\n<li><code>substr</code>和<code>substring</code>这两个方法不同的地方就在于参数二，<code>substr</code>的参数二是截取返回出来的这个字符串指定的长度，<code>substring</code>的参数二是截取返回这个字符串的结束点，并且不包含这个结束点。而它们的参数一，都是一样的功能，截取的起始位置。</li>\n<li><strong>注意事项</strong>：<code>substr</code>的参数二如果为<code>0</code>或者负数，则返回一个空字符串，如果未填入，则会截取到字符串的结尾去。<code>substring</code>的参数一和参数二为<code>NAN</code>或者负数，那么它将被替换为<code>0</code>。</li>\n</ul>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> str = <span class=\"hljs-string\">\'ABCDEFGHIJKLMN\'</span>\n<span class=\"hljs-built_in\">console</span>.log(str.substr(<span class=\"hljs-number\">2</span>))  <span class=\"hljs-comment\">// 输出 \'CDEFGHIJKLMN\'</span>\n<span class=\"hljs-built_in\">console</span>.log(str.substring(<span class=\"hljs-number\">2</span>)) <span class=\"hljs-comment\">// 输出 \'CDEFGHIJKLMN\'</span>\n\n<span class=\"hljs-built_in\">console</span>.log(str.substr(<span class=\"hljs-number\">2</span>, <span class=\"hljs-number\">9</span>))  <span class=\"hljs-comment\">// 输出 \'CDEFGHIJK\'</span>\n<span class=\"hljs-built_in\">console</span>.log(str.substring(<span class=\"hljs-number\">2</span>, <span class=\"hljs-number\">9</span>))  <span class=\"hljs-comment\">// 输出 \'CDEFGHI\'</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-22\">7.match()</h3>\n<p><code>match()</code>方法可在字符串内检索指定的值，或找到一个或多个正则表达式的匹配，并返回一个包含该搜索结果的数组。</p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> str = <span class=\"hljs-string\">\'2018年结束了，2019年开始了，2020年就也不远了\'</span>\n<span class=\"hljs-keyword\">const</span> reg = <span class=\"hljs-regexp\">/\\d+/g</span>  <span class=\"hljs-comment\">// 这里是定义匹配规则，匹配字符串里的1到多个数字</span>\n<span class=\"hljs-built_in\">console</span>.log(str.match(reg))  <span class=\"hljs-comment\">// 输出符合匹配规则的内容，以数组形式返回 [\'2018\', \'2019\', \'2020\']</span>\n<span class=\"hljs-built_in\">console</span>.log(str.match(<span class=\"hljs-string\">\'20\'</span>))  <span class=\"hljs-comment\">// 不使用正则 [\"20\", index: 0, input: \"2018年结束了，2019年开始了\"]</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<p><strong>注意事项</strong>:如果<code>match</code>方法没有找到匹配，将返回<code>null</code>。如果找到匹配，则 <code>match</code>方法会把匹配到以数组形式返回，如果正则规则未设置全局修饰符<code>g</code>，则 <code>match</code>方法返回的数组有两个特性：<code>input</code>和<code>index</code>。<code>input</code>属性包含整个被搜索的字符串。<code>index</code>属性包含了在整个被搜索字符串中匹配的子字符串的位置。</p>\n<h3 data-id=\"heading-23\">8.replace()</h3>\n<p><code>replace</code>接收两个参数，参数一是需要替换掉的字符或者一个正则的匹配规则，参数二，需要替换进去的字符，仔实际的原理当中，参数二，你可以换成一个回调函数。</p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> str = <span class=\"hljs-string\">\'2018年结束了，2019年开始了，2020年就也不远了\'</span>\n<span class=\"hljs-keyword\">const</span> rex = <span class=\"hljs-regexp\">/\\d+/g</span>  <span class=\"hljs-comment\">// 这里是定义匹配规则，匹配字符串里的1到多个数字</span>\n<span class=\"hljs-keyword\">const</span> str1 = str.replace(rex, <span class=\"hljs-string\">\'****\'</span>) \n<span class=\"hljs-built_in\">console</span>.log(str1) <span class=\"hljs-comment\">// 输出：\"****年结束了，****年开始了,****年也不远了\"</span>\n<span class=\"hljs-keyword\">const</span> str2 = str.replace(rex, <span class=\"hljs-function\"><span class=\"hljs-keyword\">function</span>(<span class=\"hljs-params\">item</span>)</span>{\n    <span class=\"hljs-built_in\">console</span>.log(<span class=\"hljs-built_in\">arguments</span>)  <span class=\"hljs-comment\">// 看下面的图片</span>\n    <span class=\"hljs-keyword\">const</span> arr = [<span class=\"hljs-string\">\'零\'</span>, <span class=\"hljs-string\">\'壹\'</span>, <span class=\"hljs-string\">\'贰\'</span>, <span class=\"hljs-string\">\'叁\'</span>, <span class=\"hljs-string\">\'肆\'</span>, <span class=\"hljs-string\">\'伍\'</span>, <span class=\"hljs-string\">\'陆\'</span>, <span class=\"hljs-string\">\'柒\'</span>, <span class=\"hljs-string\">\'捌\'</span>, <span class=\"hljs-string\">\'玖\'</span>]\n    <span class=\"hljs-keyword\">let</span> newStr = <span class=\"hljs-string\">\'\'</span>\n    item.split(<span class=\"hljs-string\">\'\'</span>).map(<span class=\"hljs-function\"><span class=\"hljs-keyword\">function</span>(<span class=\"hljs-params\">i</span>)</span>{\n            newStr += arr[i]\n    })					\n    <span class=\"hljs-keyword\">return</span> newStr       \n})\n<span class=\"hljs-built_in\">console</span>.log(str2) <span class=\"hljs-comment\">// 输出：贰零壹捌年结束了，贰零壹玖年开始了,贰零贰零年也不远了</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-24\">9.search()</h3>\n<p>在目标字符串中搜索与正则规则相匹配的字符，搜索到，则返回第一个匹配项在目标字符串当中的位置，没有搜索到则返回一个<code>-1</code>。</p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> str = <span class=\"hljs-string\">\'2018年结束了，2019年开始了，2020年就也不远了\'</span>\n<span class=\"hljs-keyword\">const</span> reg = <span class=\"hljs-regexp\">/\\d+/i</span>  <span class=\"hljs-comment\">// 这里是定义匹配规则,匹配字符串里的1到多个数字</span>\n<span class=\"hljs-built_in\">console</span>.log(str.search(reg)) <span class=\"hljs-comment\">// 输出 0  这里搜索到的第一项是从位置0开始的</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-25\">10.toLowerCase(),toUpperCase()</h3>\n<p><code>toLowerCase</code>把字母转换成小写，<code>toUpperCase()</code>则是把字母转换成大写。</p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> str1 = <span class=\"hljs-string\">\'abcdefg\'</span>\n<span class=\"hljs-keyword\">const</span> str2 = <span class=\"hljs-string\">\'ABCDEFG\'</span>\n<span class=\"hljs-built_in\">console</span>.log(str2.toLowerCase())  <span class=\"hljs-comment\">// 输出：\'abcdefg\'</span>\n<span class=\"hljs-built_in\">console</span>.log(str1.toUpperCase())  <span class=\"hljs-comment\">// 输出：\'ABCDEFG\'</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-26\">11.includes(), startsWith(), endsWith()</h3>\n<p><code>includes</code>、<code>startsWith</code>、<code>endsWith</code>，<code>es6</code>的新增方法，<code>includes</code> 用来检测目标字符串对象是否包含某个字符，返回一个布尔值，<code>startsWith</code>用来检测当前字符是否是目标字符串的起始部分，相对的<code>endwith</code>是用来检测是否是目标字符串的结尾部分。</p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> str = <span class=\"hljs-string\">\'Excuse me, how do I get to park road?\'</span>\n<span class=\"hljs-built_in\">console</span>.log(str.includes(<span class=\"hljs-string\">\'how\'</span>)) <span class=\"hljs-comment\">// 输出：true</span>\n<span class=\"hljs-built_in\">console</span>.log(str.startsWith(<span class=\"hljs-string\">\'Excuse\'</span>)) <span class=\"hljs-comment\">// 输出： true</span>\n<span class=\"hljs-built_in\">console</span>.log(str.endsWith(<span class=\"hljs-string\">\'?\'</span>)) <span class=\"hljs-comment\">// 输出： true</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-27\">12.repeat()</h3>\n<p>返回一个新的字符串对象，新字符串等于重复了指定次数的原始字符串。接收一个参数，就是指定重复的次数。原字符串不变。</p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> str = <span class=\"hljs-string\">\'http\'</span>\n<span class=\"hljs-keyword\">const</span> str2 = str.repeat(<span class=\"hljs-number\">3</span>)\n<span class=\"hljs-built_in\">console</span>.log(str) <span class=\"hljs-comment\">// 输出：\'http\'</span>\n<span class=\"hljs-built_in\">console</span>.log(str2) <span class=\"hljs-comment\">// 输出：\'httphttphttp\'</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h2 data-id=\"heading-28\">三、常用遍历方法&amp;高阶函数</h2>\n<h3 data-id=\"heading-29\">1.for()</h3>\n<p>最常用的<code>for</code>循环，经常用的数组遍历，也可以遍历字符串。</p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> arr = [<span class=\"hljs-number\">1</span>, <span class=\"hljs-number\">2</span>, <span class=\"hljs-number\">3</span>]\n<span class=\"hljs-keyword\">const</span> str = <span class=\"hljs-string\">\'abc\'</span>\n<span class=\"hljs-keyword\">for</span> (<span class=\"hljs-keyword\">let</span> i = <span class=\"hljs-number\">0</span>; i &lt; arr.length; i++) {\n    <span class=\"hljs-built_in\">console</span>.log(arr[i])\n    <span class=\"hljs-built_in\">console</span>.log(str[i])\n}\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-30\">2.while() / do while()</h3>\n<p><code>while</code>、<code>do while</code>主要的功能是，当满足<code>while</code>后边所跟的条件时，来执行相关业务。这两个的区别是，<code>while</code>会先判断是否满足条件，然后再去执行花括号里面的任务，而<code>do while</code>则是先执行一次花括号中的任务，再去执行<code>while</code>条件，判断下次还是否再去执行<code>do</code>里面的操作。也就是说 <strong><code>do while</code>至少会执行一次操作</strong>.</p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">while</span>(条件){\n     执行...\n}\n------------\n<span class=\"hljs-keyword\">do</span>{\n    执行...\n}\n<span class=\"hljs-keyword\">while</span>(条件)\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-31\">3.forEach()</h3>\n<p>拷贝一份遍历原数组。</p>\n<ul>\n<li><code>return</code>无法终止循环。不过可以起到<code>continue</code>效果。</li>\n<li>本身是不支持的<code>continue</code>与<code>break</code>语句的我们可以通过<code>some</code>和&nbsp;<code>every</code>来实现。</li>\n</ul>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> arr = [<span class=\"hljs-number\">5</span>,<span class=\"hljs-number\">1</span>,<span class=\"hljs-number\">3</span>,<span class=\"hljs-number\">7</span>,<span class=\"hljs-number\">4</span>]\narr.forEach(<span class=\"hljs-function\">(<span class=\"hljs-params\">item, index</span>) =&gt;</span> {\n    <span class=\"hljs-keyword\">if</span> (item &lt; <span class=\"hljs-number\">2</span>) <span class=\"hljs-keyword\">return</span>\n    <span class=\"hljs-built_in\">console</span>.log(<span class=\"hljs-string\">`索引：<span class=\"hljs-subst\">${index}</span>，数值：<span class=\"hljs-subst\">${item}</span>`</span>)\n    arr[<span class=\"hljs-number\">5</span>] = <span class=\"hljs-number\">0</span>\n})\n<span class=\"hljs-built_in\">console</span>.log(arr)\n<span class=\"hljs-comment\">// 打印结果：</span>\n<span class=\"hljs-comment\">// 索引：0，数值：5</span>\n<span class=\"hljs-comment\">// 索引：2，数值：3</span>\n<span class=\"hljs-comment\">// 索引：3，数值：7</span>\n<span class=\"hljs-comment\">// 索引：4，数值：4</span>\n<span class=\"hljs-comment\">// [5, 1, 3, 7, 4, 0]</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-32\">4.for...in</h3>\n<ul>\n<li><code>for...in</code> 是 ES5 标准， 此方法遍历数组效率低，主要是用来循环遍历对象的属性。</li>\n<li>遍历数组的缺点：数组的下标<code>index</code>值是数字，<code>for-in</code>遍历的<code>index</code>值<code>\"0\",\"1\",\"2\"</code>等是字符串。</li>\n<li><code>Object.defineProperty</code>，建立的属性，默认不可枚举。</li>\n</ul>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> foo = {\n    <span class=\"hljs-attr\">name</span>: <span class=\"hljs-string\">\'bar\'</span>,\n    <span class=\"hljs-attr\">sex</span>: <span class=\"hljs-string\">\'male\'</span>\n}\n<span class=\"hljs-built_in\">Object</span>.defineProperty(foo, <span class=\"hljs-string\">\"age\"</span>, { <span class=\"hljs-attr\">value</span> : <span class=\"hljs-number\">18</span> })\n<span class=\"hljs-keyword\">for</span>(<span class=\"hljs-keyword\">const</span> key <span class=\"hljs-keyword\">in</span> foo){\n    <span class=\"hljs-built_in\">console</span>.log(<span class=\"hljs-string\">`可枚举属性：<span class=\"hljs-subst\">${key}</span>`</span>)\n}\n<span class=\"hljs-built_in\">console</span>.log(<span class=\"hljs-string\">`age属性：<span class=\"hljs-subst\">${foo.age}</span>`</span>)\n<span class=\"hljs-comment\">// 打印结果：</span>\n<span class=\"hljs-comment\">// 可枚举属性：name</span>\n<span class=\"hljs-comment\">// 可枚举属性：sex</span>\n<span class=\"hljs-comment\">// age属性：18</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-33\">5.for...of</h3>\n<p><code>for…of</code>是<code>ES6</code>新增的方法，但是<code>for…of</code>不能去遍历普通的对象，<strong><code>for…of</code>的好处是可以使用<code>break</code>跳出循环。</strong></p>\n<ul>\n<li>\n<p><code>for-of</code>这个方法避开了<code>for-in</code>循环的所有缺陷</p>\n</li>\n<li>\n<p>与<code>forEach()</code>不同的是，它可以正确响应<code>break</code>、<code>continue</code>和<code>return</code>语句&nbsp;</p>\n</li>\n<li>\n<p><code>for-of</code>循环不仅支持数组，还支持大多数类数组对象，例如<code>DOM</code>&nbsp;<a href=\"https://link.juejin.cn?target=https%3A%2F%2Fdeveloper.mozilla.org%2Fen-US%2Fdocs%2FWeb%2FAPI%2FNodeList\" target=\"_blank\" rel=\"nofollow noopener noreferrer\" title=\"https://developer.mozilla.org/en-US/docs/Web/API/NodeList\" ref=\"nofollow noopener noreferrer\">NodeList对象</a>。</p>\n</li>\n<li>\n<p><code>for-of</code>循环也支持字符串遍历</p>\n</li>\n</ul>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-comment\">// for of 循环直接得到的就是值</span>\n<span class=\"hljs-keyword\">const</span> arr = [<span class=\"hljs-number\">1</span>, <span class=\"hljs-number\">2</span>, <span class=\"hljs-number\">3</span>]\n<span class=\"hljs-keyword\">for</span> (<span class=\"hljs-keyword\">const</span> value <span class=\"hljs-keyword\">of</span> arr) {\n <span class=\"hljs-built_in\">console</span>.log(value)\n}\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<p><strong>面试官：说一下 <code>for...in</code> 和 <code>for...of</code> 区别？</strong></p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\">（<span class=\"hljs-number\">1</span>）<span class=\"hljs-keyword\">for</span>…<span class=\"hljs-keyword\">in</span> 用于可枚举数据，如对象、数组、字符串\n（<span class=\"hljs-number\">2</span>）<span class=\"hljs-keyword\">for</span>…<span class=\"hljs-keyword\">of</span> 用于可迭代数据，如数组、字符串、<span class=\"hljs-built_in\">Map</span>、<span class=\"hljs-built_in\">Set</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-34\">6.every / some</h3>\n<p><strong>返回一个布尔值</strong>。当我们需要判定数组中的元素是否满足某些条件时，可以使用<code>every</code> / <code>some</code>。这两个的区别是，<code>every</code>会去判断判断数组中的每一项，而 <code>some</code>则是当某一项满足条件时返回。</p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-comment\">// every</span>\n<span class=\"hljs-keyword\">const</span> foo = [<span class=\"hljs-number\">5</span>,<span class=\"hljs-number\">1</span>,<span class=\"hljs-number\">3</span>,<span class=\"hljs-number\">7</span>,<span class=\"hljs-number\">4</span>].every(<span class=\"hljs-function\">(<span class=\"hljs-params\">item, index</span>) =&gt;</span> {\n    <span class=\"hljs-built_in\">console</span>.log(<span class=\"hljs-string\">`索引：<span class=\"hljs-subst\">${index}</span>，数值：<span class=\"hljs-subst\">${item}</span>`</span>)\n    <span class=\"hljs-keyword\">return</span> item &gt; <span class=\"hljs-number\">2</span>\n})\n<span class=\"hljs-built_in\">console</span>.log(foo)\n<span class=\"hljs-comment\">// every 打印：</span>\n<span class=\"hljs-comment\">// 索引：0，数值：5</span>\n<span class=\"hljs-comment\">// 索引：1，数值：1</span>\n<span class=\"hljs-comment\">// false</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-comment\">// some</span>\n<span class=\"hljs-keyword\">const</span> foo = [<span class=\"hljs-number\">5</span>,<span class=\"hljs-number\">1</span>,<span class=\"hljs-number\">3</span>,<span class=\"hljs-number\">7</span>,<span class=\"hljs-number\">4</span>].some(<span class=\"hljs-function\">(<span class=\"hljs-params\">item, index</span>) =&gt;</span> {\n    <span class=\"hljs-built_in\">console</span>.log(<span class=\"hljs-string\">`索引：<span class=\"hljs-subst\">${index}</span>，数值：<span class=\"hljs-subst\">${item}</span>`</span>)\n    <span class=\"hljs-keyword\">return</span> item &gt; <span class=\"hljs-number\">2</span>\n})\n<span class=\"hljs-built_in\">console</span>.log(foo)\n<span class=\"hljs-comment\">// some 打印：</span>\n<span class=\"hljs-comment\">// 索引：0，数值：5</span>\n<span class=\"hljs-comment\">// true</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-35\">7.filter()</h3>\n<ul>\n<li><code>filter</code>方法用于过滤数组成员，满足条件的成员组成一个新数组返回。</li>\n<li>它的参数是一个函数，所有数组成员依次执行该函数，返回结果为<code>true</code>的成员组成一个新数组返回。</li>\n<li>该方法不会改变原数组。</li>\n</ul>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> foo = [<span class=\"hljs-number\">5</span>,<span class=\"hljs-number\">1</span>,<span class=\"hljs-number\">3</span>,<span class=\"hljs-number\">7</span>,<span class=\"hljs-number\">4</span>].filter(<span class=\"hljs-function\">(<span class=\"hljs-params\">item,index</span>) =&gt;</span> {\n    <span class=\"hljs-built_in\">console</span>.log(<span class=\"hljs-string\">`索引：<span class=\"hljs-subst\">${index}</span>，数值：<span class=\"hljs-subst\">${item}</span>`</span>)\n    <span class=\"hljs-keyword\">return</span> item &gt; <span class=\"hljs-number\">2</span>\n})\n<span class=\"hljs-built_in\">console</span>.log(foo)\n<span class=\"hljs-comment\">// 打印结果：</span>\n<span class=\"hljs-comment\">// 索引：0，数值：5</span>\n<span class=\"hljs-comment\">// 索引：1，数值：1</span>\n<span class=\"hljs-comment\">// 索引：2，数值：3</span>\n<span class=\"hljs-comment\">// 索引：3，数值：7</span>\n<span class=\"hljs-comment\">// 索引：4，数值：4</span>\n<span class=\"hljs-comment\">// [5, 3, 7, 4]</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-36\">8.map()</h3>\n<ul>\n<li><code>map</code>即是 “映射”的意思 ，原数组被“映射”成对应新数组。</li>\n<li><code>map：</code>支持<code>return</code>，相当与原数组克隆了一份，把克隆的每项改变了，也不影响原数组。</li>\n</ul>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> foo = [<span class=\"hljs-number\">5</span>,<span class=\"hljs-number\">1</span>,<span class=\"hljs-number\">3</span>,<span class=\"hljs-number\">7</span>,<span class=\"hljs-number\">4</span>].map(<span class=\"hljs-function\">(<span class=\"hljs-params\">item,index</span>) =&gt;</span> {\n    <span class=\"hljs-built_in\">console</span>.log(<span class=\"hljs-string\">`索引：<span class=\"hljs-subst\">${index}</span>，数值：<span class=\"hljs-subst\">${item}</span>`</span>)\n    <span class=\"hljs-keyword\">return</span> item + <span class=\"hljs-number\">2</span>\n})\n<span class=\"hljs-built_in\">console</span>.log(foo)\n<span class=\"hljs-comment\">// 打印结果：</span>\n<span class=\"hljs-comment\">// 索引：0，数值：5</span>\n<span class=\"hljs-comment\">// 索引：1，数值：1</span>\n<span class=\"hljs-comment\">// 索引：2，数值：3</span>\n<span class=\"hljs-comment\">// 索引：3，数值：7</span>\n<span class=\"hljs-comment\">// 索引：4，数值：4</span>\n<span class=\"hljs-comment\">// [7, 3, 5, 9, 6]</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-37\">9. reduce() / reduceRight()</h3>\n<p><code>reduce</code> 从左到右将数组元素做“叠加”处理，返回一个值。<code>reduceRight</code> 从右到左。</p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> foo = [<span class=\"hljs-number\">5</span>,<span class=\"hljs-number\">1</span>,<span class=\"hljs-number\">3</span>,<span class=\"hljs-number\">7</span>,<span class=\"hljs-number\">4</span>].reduce(<span class=\"hljs-function\">(<span class=\"hljs-params\">total, cur</span>) =&gt;</span> {\n    <span class=\"hljs-built_in\">console</span>.log(<span class=\"hljs-string\">`叠加：<span class=\"hljs-subst\">${total}</span>，当前：<span class=\"hljs-subst\">${cur}</span>`</span>)\n    <span class=\"hljs-keyword\">return</span> total + cur\n})\n<span class=\"hljs-built_in\">console</span>.log(foo)\n<span class=\"hljs-comment\">// 打印结果：</span>\n<span class=\"hljs-comment\">// 叠加：5，当前：1</span>\n<span class=\"hljs-comment\">// 叠加：6，当前：3</span>\n<span class=\"hljs-comment\">// 叠加：9，当前：7</span>\n<span class=\"hljs-comment\">// 叠加：16，当前：4</span>\n<span class=\"hljs-comment\">// 20</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-38\">10.Object,keys遍历对象的属性</h3>\n<p><code>Object.keys</code>方法的参数是一个对象，返回一个数组。该数组的成员都是该对象自身的（而不是继承的）所有属性名，且只返回可枚举的属性。</p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> obj = {\n  <span class=\"hljs-attr\">p1</span>: <span class=\"hljs-number\">123</span>,\n  <span class=\"hljs-attr\">p2</span>: <span class=\"hljs-number\">456</span>\n};\n<span class=\"hljs-built_in\">Object</span>.keys(obj) <span class=\"hljs-comment\">// [\"p1\", \"p2\"]</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-39\">11.Object.getOwnPropertyNames() 遍历对象的属性</h3>\n<p><code>Object.getOwnPropertyNames</code>方法与<code>Object.keys</code>类似，也是接受一个对象作为参数，返回一个数组，包含了该对象自身的所有属性名。但它能返回不可枚举的属性。</p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-keyword\">const</span> arr = [<span class=\"hljs-string\">\'Hello\'</span>, <span class=\"hljs-string\">\'World\'</span>];\n<span class=\"hljs-built_in\">Object</span>.keys(arr) <span class=\"hljs-comment\">// [\"0\", \"1\"]</span>\n<span class=\"hljs-built_in\">Object</span>.getOwnPropertyNames(arr) <span class=\"hljs-comment\">// [\"0\", \"1\", \"length\"]</span>\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-40\">以上遍历方法的区别：</h3>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\">一：map()，forEach()，filter()循环的共同之处：\n  <span class=\"hljs-number\">1.</span>forEach，map，filter循环中途是无法停止的，总是会将所有成员遍历完。\n  <span class=\"hljs-number\">2.</span>他们都可以接受第二个参数，用来绑定回调函数内部的 <span class=\"hljs-built_in\">this</span> 变量，将回调函数内部的 <span class=\"hljs-built_in\">this</span> 对象，指向第二个参数，间接操作这个参数（一般是数组）。\n\n二：map()、filter()循环和forEach()循环的不同：\n   forEach 循环没有返回值； map，filter 循环有返回值。\n\n三：map()和filter()都会跳过空位，<span class=\"hljs-keyword\">for</span> 和 <span class=\"hljs-keyword\">while</span> 不会\n\n四：some()和every():\n   some()只要有一个是<span class=\"hljs-literal\">true</span>，便返回<span class=\"hljs-literal\">true</span>；而every()只要有一个是<span class=\"hljs-literal\">false</span>，便返回<span class=\"hljs-literal\">false</span>.\n\n五：reduce()，reduceRight()：\n   reduce是从左到右处理（从第一个成员到最后一个成员），reduceRight则是从右到左（从最后一个成员到第一个成员）。\n\n六：<span class=\"hljs-built_in\">Object</span>对象的两个遍历 <span class=\"hljs-built_in\">Object</span>.keys 与 <span class=\"hljs-built_in\">Object</span>.getOwnPropertyNames：\n   他们都是遍历对象的属性，也是接受一个对象作为参数，返回一个数组，包含了该对象自身的所有属性名。但<span class=\"hljs-built_in\">Object</span>.keys不能返回不可枚举的属性；<span class=\"hljs-built_in\">Object</span>.getOwnPropertyNames能返回不可枚举的属性。\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h2 data-id=\"heading-41\">四、常用正则表达式</h2>\n<p>这里罗列一些我在刷算法题中遇到的正则表达式，如果有时间可认真学一下<a href=\"https://juejin.cn/post/6844903845227659271\" target=\"_blank\" title=\"https://juejin.cn/post/6844903845227659271\">正则表达式不要背</a>。</p>\n<h3 data-id=\"heading-42\">1.判断字符</h3>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\">由<span class=\"hljs-number\">26</span>个英文字母组成的字符串：^[A-Za-z]+$\n由<span class=\"hljs-number\">26</span>个大写英文字母组成的字符串：^[A-Z]+$\n由<span class=\"hljs-number\">26</span>个小写英文字母组成的字符串：^[a-z]+$\n由数字和<span class=\"hljs-number\">26</span>个英文字母组成的字符串：^[A-Za-z0-<span class=\"hljs-number\">9</span>]+$\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-43\">2.判断数字</h3>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\">数字：^[<span class=\"hljs-number\">0</span>-<span class=\"hljs-number\">9</span>]*$\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<p>持续更新，敬请期待……</p>\n<h2 data-id=\"heading-44\">五、数学知识</h2>\n<h3 data-id=\"heading-45\">1.质数</h3>\n<p>若一个正整数无法被除了<code>1</code> 和它自身之外的任何自然数整除，则称该数为质数（或素数），否则称该正整数为合数。</p>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-function\"><span class=\"hljs-keyword\">function</span> <span class=\"hljs-title\">judgePrime</span>(<span class=\"hljs-params\">n</span>) </span>{\n    <span class=\"hljs-keyword\">for</span> (<span class=\"hljs-keyword\">let</span> i = <span class=\"hljs-number\">2</span>; i * i &lt;= n; i++) {\n        <span class=\"hljs-keyword\">if</span> (n % i == <span class=\"hljs-number\">0</span>) <span class=\"hljs-keyword\">return</span> <span class=\"hljs-literal\">false</span>\n    }\n    <span class=\"hljs-keyword\">return</span> <span class=\"hljs-literal\">true</span>\n}\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<h3 data-id=\"heading-46\">2.斐波那契数列</h3>\n<pre><code class=\"hljs language-js copyable\" lang=\"js\"><span class=\"hljs-function\"><span class=\"hljs-keyword\">function</span> <span class=\"hljs-title\">Fibonacci</span>(<span class=\"hljs-params\">n</span>) </span>{\n    <span class=\"hljs-keyword\">if</span> (n &lt;= <span class=\"hljs-number\">1</span>) <span class=\"hljs-keyword\">return</span> n  \n    <span class=\"hljs-keyword\">return</span> Fibonacci(n - <span class=\"hljs-number\">1</span>) + Fibonacci(n - <span class=\"hljs-number\">2</span>)\n}\n<span class=\"copy-code-btn\">复制代码</span></code></pre>\n<p>持续更新，敬请期待……</p>\n<h2 data-id=\"heading-47\">参考文章</h2>\n<ul>\n<li><a href=\"https://juejin.cn/post/6844903683990241293\" target=\"_blank\" title=\"https://juejin.cn/post/6844903683990241293\">JavaScript 之字符串常用方法</a></li>\n<li><a href=\"https://link.juejin.cn?target=https%3A%2F%2Fcloud.tencent.com%2Fdeveloper%2Farticle%2F1589766\" target=\"_blank\" rel=\"nofollow noopener noreferrer\" title=\"https://cloud.tencent.com/developer/article/1589766\" ref=\"nofollow noopener noreferrer\">JavaScript 循环遍历大全</a></li>\n<li><a href=\"https://link.juejin.cn?target=https%3A%2F%2Fzhuanlan.zhihu.com%2Fp%2F301338035\" target=\"_blank\" rel=\"nofollow noopener noreferrer\" title=\"https://zhuanlan.zhihu.com/p/301338035\" ref=\"nofollow noopener noreferrer\">刷算法题必备的数学考点汇总</a></li>\n</ul><style>.markdown-body pre,.markdown-body pre>code.hljs{color:#333;background:#f8f8f8}.hljs-comment,.hljs-quote{color:#998;font-style:italic}.hljs-keyword,.hljs-selector-tag,.hljs-subst{color:#333;font-weight:700}.hljs-literal,.hljs-number,.hljs-tag .hljs-attr,.hljs-template-variable,.hljs-variable{color:teal}.hljs-doctag,.hljs-string{color:#d14}.hljs-section,.hljs-selector-id,.hljs-title{color:#900;font-weight:700}.hljs-subst{font-weight:400}.hljs-class .hljs-title,.hljs-type{color:#458;font-weight:700}.hljs-attribute,.hljs-name,.hljs-tag{color:navy;font-weight:400}.hljs-link,.hljs-regexp{color:#009926}.hljs-bullet,.hljs-symbol{color:#990073}.hljs-built_in,.hljs-builtin-name{color:#0086b3}.hljs-meta{color:#999;font-weight:700}.hljs-deletion{background:#fdd}.hljs-addition{background:#dfd}.hljs-emphasis{font-style:italic}.hljs-strong{font-weight:700}</style></div></div> <div data-v-3fbea7fe=\"\" class=\"tag-list-box\"><div data-v-3fbea7fe=\"\" class=\"tag-list\"><div data-v-3fbea7fe=\"\" class=\"tag-list-title\">分类：</div> <a data-v-3fbea7fe=\"\" href=\"/frontend\" target=\"_blank\" rel=\"\" class=\"item category-item\"><span data-v-3fbea7fe=\"\" class=\"tag-title\">前端</span></a></div> <div data-v-3fbea7fe=\"\" class=\"tag-list\"><div data-v-3fbea7fe=\"\" class=\"tag-list-title\">标签：</div> <div data-v-3fbea7fe=\"\" class=\"tag-list-container\"><a data-v-3fbea7fe=\"\" href=\"/tag/%E5%89%8D%E7%AB%AF\" target=\"_blank\" rel=\"\" class=\"item tag-item\"><span data-v-3fbea7fe=\"\" class=\"tag-title\">前端</span></a><a data-v-3fbea7fe=\"\" href=\"/tag/%E7%AE%97%E6%B3%95\" target=\"_blank\" rel=\"\" class=\"item tag-item\"><span data-v-3fbea7fe=\"\" class=\"tag-title\">算法</span></a></div></div></div> <div data-v-90e996fc=\"\" data-v-3fbea7fe=\"\" class=\"column-container\"><div data-v-90e996fc=\"\" class=\"column-header\"><span data-v-90e996fc=\"\" class=\"column-title\">文章被收录于专栏：</span></div> <div data-v-90e996fc=\"\" class=\"column-content\"><div data-v-79b79a50=\"\" data-v-90e996fc=\"\" class=\"item-container\"><img data-v-0808752c=\"\" data-v-79b79a50=\"\" src=\"https://p1-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/95414745836549ce9143753e2a30facd~tplv-k3u1fbpfcp-no-mark:160:160:160:120.awebp\" data-src=\"https://p1-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/95414745836549ce9143753e2a30facd~tplv-k3u1fbpfcp-no-mark:160:160:160:120.awebp\" alt=\"cover\" loading=\"lazy\" class=\"lazy\"> <div data-v-79b79a50=\"\" class=\"content\"><div data-v-79b79a50=\"\" class=\"title\">\n      前端算法·入门知识\n    </div> <div data-v-79b79a50=\"\" class=\"description\">\n      主要普及刷前端算法题的一些前置知识。\n    </div></div> <!----> <!----> <button data-v-47fb9395=\"\" data-v-79b79a50=\"\" class=\"ui-btn btn follow-btn primary mini default attention\"><!----> \n    关注专栏\n  </button></div></div></div> <!----></article>', NULL, NULL, NULL, 0, '0', '1', 1, 'juejin', '', 7012161541378146350, NULL, '2022-03-15 16:19:59.023590', '2022-04-24 10:02:58.059746');
